// MAIN INITIALIZATION
export function initLoader(heroImagePromise) {

    let isImageReady = false;

    //Safely check if the promise exists before calling .then()
    if (heroImagePromise) {
        heroImagePromise.then(() => { isImageReady = true; });
    } else {
        isImageReady = true; // Safe fallback so it never freezes
    }

    // DOM Elements Setup
    const overlay = document.createElement("div");
    overlay.style.position = "fixed";
    overlay.style.top = "0";
    overlay.style.left = "0";
    overlay.style.right = "0";
    overlay.style.bottom = "0";
    overlay.style.backgroundImage = `
    repeating-linear-gradient(0deg, #ffffff05, #ffffff05 1px, transparent 1px, transparent 8px),
    radial-gradient(circle, rgb(23, 24, 39) 0%, rgba(0, 0, 0, 1) 100%)
    `;
    overlay.style.zIndex = "99999";
    overlay.style.display = "flex";
    overlay.style.justifyContent = "center";
    overlay.style.alignItems = "center";
    overlay.style.transition = `opacity ${TIME_TO_FADEOUT}ms ease-out`;

    const logoContainer = document.createElement("div");
    logoContainer.style.maxWidth = "300px";
    logoContainer.style.zIndex = "2";

    // Inject the SVG directly into the DOM instead of an img tag
    logoContainer.innerHTML = ANIM_SVG_LOGO;
    const svgElement = logoContainer.querySelector('svg');
    svgElement.style.display = "block";
    svgElement.style.width = "300px";
    svgElement.style.overflow = "visible"; // Prevents stroke clipping at edges

    // Add the glow effect
    svgElement.style.filter = "drop-shadow(0px 0px 8px rgba(255, 255, 255, 0.5))";

    overlay.appendChild(logoContainer);

    const loadingBar = document.createElement("div");
    loadingBar.style.position = "absolute";
    loadingBar.style.bottom = "0";
    loadingBar.style.left = "0";
    loadingBar.style.width = "100%";
    loadingBar.style.height = "100%";
    loadingBar.style.backgroundColor = LOADER_BAR_COLOR;
    loadingBar.style.zIndex = "1";
    loadingBar.style.transformOrigin = "bottom left";

    const initialScaleY = parseInt(BAR_INITIAL_HEIGHT) / window.innerHeight;
    loadingBar.style.transform = `scale(0, ${initialScaleY})`;
    overlay.appendChild(loadingBar);

    const percentageText = document.createElement("div");
    percentageText.style.position = "absolute";
    percentageText.style.bottom = `calc(${BAR_INITIAL_HEIGHT} + 8px)`;
    percentageText.style.left = "0";
    percentageText.style.color = LOADER_BAR_COLOR;
    percentageText.style.fontFamily = "sans-serif";
    percentageText.style.fontWeight = "bold";
    percentageText.style.fontSize = "18px";
    percentageText.style.zIndex = "2";
    percentageText.style.transition = `opacity 0.3s ease`;
    percentageText.innerText = "0%";
    percentageText.style.transform = "translateX(0)";
    overlay.appendChild(percentageText);

    // Dynamic CSS logic to control the draw and fill sequence
    const style = document.createElement("style");
    style.textContent = `
        .logo-path {
            stroke: #fff;
            stroke-width: 3px;
            fill: transparent;
            stroke-dasharray: var(--path-length);
            stroke-dashoffset: var(--path-length);
            animation: drawOutline ${TIME_TO_LOAD}ms ease-in-out forwards;
            
            transition: fill ${TIME_TO_FILL}ms ease-in-out;
        }
        .logo-path.fill-active {
            fill: #fff;
        }
        @keyframes drawOutline {
            0% { stroke-dashoffset: var(--path-length); }
            100% { stroke-dashoffset: 0; }
        }
    `;
    document.head.appendChild(style);
    document.body.appendChild(overlay);

    // We must calculate the path length AFTER the node is appended to document.body, 
    // otherwise the browser's get length API might return 0
    const paths = logoContainer.querySelectorAll('.logo-path');
    paths.forEach(path => {
        const pathLength = path.getTotalLength();
        path.style.setProperty('--path-length', pathLength);
    });

    // Animation Sequence Math
    let currentProgress = 0;
    let lastTime = performance.now();

    const updateProgress = (timestamp) => {
        const deltaTime = timestamp - lastTime;
        lastTime = timestamp;

        let progressStep = (100 / TIME_TO_LOAD) * deltaTime;

        if (currentProgress < 99) {
            currentProgress += progressStep;
        } else if (currentProgress >= 99 && currentProgress < 100) {
            if (isImageReady) {
                currentProgress += progressStep * 2;
            } else {
                currentProgress = 99;
            }
        }

        currentProgress = Math.min(currentProgress, 100);

        loadingBar.style.transform = `scale(${currentProgress / 100}, ${initialScaleY})`;
        percentageText.innerText = Math.floor(currentProgress) + "%";
        percentageText.style.transform = `translateX(calc(${currentProgress}vw - ${currentProgress}%))`;

        if (currentProgress < 100) {
            window.requestAnimationFrame(updateProgress);
        } else {
            triggerNextPhase();
        }
    };

    window.requestAnimationFrame(updateProgress);

    function triggerNextPhase() {
        percentageText.style.opacity = "0";

        // This triggers the CSS "fill" transition instead of jumping
        const paths = logoContainer.querySelectorAll('.logo-path');
        paths.forEach(path => path.classList.add('fill-active'));

        setTimeout(() => {
            loadingBar.style.transition = `transform ${TIME_TO_EXPAND}ms cubic-bezier(0.65, 0, 0.35, 1)`;
            loadingBar.style.transform = `scale(1, 1)`;

            logoContainer.style.transition = `opacity ${TIME_TO_EXPAND / 2}ms ease`;
            logoContainer.style.opacity = "0";

            setTimeout(() => {
                overlay.style.opacity = "0";

                setTimeout(() => {
                    overlay.remove();

                    window.isLoaderActive = false;
                    document.body.style.overflow = '';

                    if (typeof window.lenis !== 'undefined') {
                        window.lenis.start();
                    }

                    // --- Fire Parallax Event ---
                    window.dispatchEvent(new CustomEvent('loaderFinished'));

                }, TIME_TO_FADEOUT);

            }, TIME_TO_EXPAND);

        }, TIME_TO_FILL); // Using the fill duration here to pause before expansion

        setTimeout(() => {
            const heroText = document.querySelector('.typewriter');
            if (heroText) {
                heroText.classList.add('is-typing');
            }
        }, 1800);
    }
}